)
def main(verbose: int) -> None:
    """Jeltz — MCP gateway for physical devices."""
    level = _LOG_LEVELS.get(verbose, logging.DEBUG)
    logging.basicConfig(
        level=level,
        format="%(levelname)s %(name)s: %(message)s",
    )


@main.command()
@click.option(
    "--profiles-dir",
    "-p",
