    uint8_t _toolCount;
    const char* _healthCmd;
    const char* _healthExpect;
    uint16_t _healthIntervalMs;

    /**
     * Serialize the device description as compact JSON and write it
     * directly to the serial port. No intermediate buffer needed —
     * ArduinoJson streams to the Print interface.
     */
    void _sendDescribe() {
        if (!_serial) return;

        JsonDocument doc;

        doc["v"] = JELTZ_PROTOCOL_VERSION;
        doc["name"] = _name;
        if (_desc && _desc[0] != '\0') {
            doc["desc"] = _desc;
        }

        // Health config
        if (_healthCmd) {
            JsonObject h = doc["health"].to<JsonObject>();
            h["cmd"] = _healthCmd;
            h["expect"] = _healthExpect;
            h["ms"] = _healthIntervalMs;
        }

        // Tools
        JsonArray toolsArr = doc["tools"].to<JsonArray>();
        for (uint8_t i = 0; i < _toolCount; i++) {
            const JeltzTool& t = _tools[i];
            JsonObject toolObj = toolsArr.add<JsonObject>();

            toolObj["name"] = t.name;
            if (t.desc && t.desc[0] != '\0') {
                toolObj["desc"] = t.desc;
            }
            if (t.cmd) {
                toolObj["cmd"] = t.cmd;
            }

            // Parameters
            if (t.paramCount > 0) {
                JsonObject paramsObj = toolObj["params"].to<JsonObject>();
                for (uint8_t j = 0; j < t.paramCount; j++) {
                    const JeltzParam& p = t.params[j];
                    JsonObject paramObj = paramsObj[p.name].to<JsonObject>();
                    paramObj["type"] = p.type;
                    if (p.desc) {
                        paramObj["desc"] = p.desc;
                    }
                    if (p.hasRange) {
                        paramObj["min"] = p.minVal;
                        paramObj["max"] = p.maxVal;
                    }
                }
            }

            // Returns
            if (t.hasReturns) {
                JsonObject retObj = toolObj["returns"].to<JsonObject>();
                retObj["type"] = t.returns.type;
                if (t.returns.unit) {
                    retObj["unit"] = t.returns.unit;
                }
            }
        }

