/*
 * Jeltz — self-describing MCP device library for Arduino.
 *
 * Lets devices describe their capabilities to a Jeltz gateway over serial.
 * The gateway sends JELTZ_DESCRIBE, the device responds with JSON, and from
 * that point on commands use the standard text protocol.
 *
 * https://github.com/heath0xFF/jeltz-arduino
 * Apache 2.0
 */

#ifndef JELTZ_H
#define JELTZ_H

#include <Arduino.h>
#include <ArduinoJson.h>

#ifndef JELTZ_MAX_TOOLS
#define JELTZ_MAX_TOOLS 8
#endif

#ifndef JELTZ_MAX_PARAMS
#define JELTZ_MAX_PARAMS 4
#endif

#define JELTZ_PROTOCOL_VERSION 1
#define JELTZ_DESCRIBE_CMD "JELTZ_DESCRIBE"

struct JeltzParam {
    const char* name;
    const char* type;       // "int", "float", "str", "bool"
    const char* desc;       // nullable
    float minVal;
    float maxVal;
    bool hasRange;
};

struct JeltzReturns {
    const char* type;       // "int", "float", "str", "bool"
    const char* unit;       // nullable — "celsius", "percent", etc.
};

struct JeltzTool {
    const char* name;
    const char* desc;
    const char* cmd;
    JeltzReturns returns;
    JeltzParam params[JELTZ_MAX_PARAMS];
    uint8_t paramCount;
    bool hasReturns;
};

class Jeltz;

class ToolBuilder {
public:
    ToolBuilder(JeltzTool* tool) : _tool(tool) {}

    ToolBuilder& command(const char* cmd) {
        _tool->cmd = cmd;
        return *this;
    }

    ToolBuilder& param(const char* name, const char* type,
                       const char* desc = nullptr,
                       float minVal = 0, float maxVal = 0) {
        if (_tool->paramCount < JELTZ_MAX_PARAMS) {
            JeltzParam& p = _tool->params[_tool->paramCount++];
            p.name = name;
            p.type = type;
            p.desc = desc;
            p.minVal = minVal;
            p.maxVal = maxVal;
            p.hasRange = (minVal != 0 || maxVal != 0);
        }
        return *this;
    }

    ToolBuilder& returns(const char* type, const char* unit = nullptr) {
        _tool->returns.type = type;
        _tool->returns.unit = unit;
        _tool->hasReturns = true;
        return *this;
    }

private:
    JeltzTool* _tool;
};

class Jeltz {
public:
    Jeltz(const char* name, const char* description = "")
        : _name(name), _desc(description), _serial(nullptr),
          _toolCount(0), _healthCmd(nullptr), _healthExpect(nullptr),
          _healthIntervalMs(10000) {}

    /**
     * Register a tool on this device. Returns a ToolBuilder for chaining
     * .command(), .param(), and .returns().
     */
    ToolBuilder tool(const char* name, const char* description) {
        if (_toolCount < JELTZ_MAX_TOOLS) {
            JeltzTool& t = _tools[_toolCount++];
            t.name = name;
            t.desc = description;
            t.cmd = nullptr;
            t.paramCount = 0;
            t.hasReturns = false;
            t.returns.type = nullptr;
            t.returns.unit = nullptr;
            return ToolBuilder(&t);
        }
        // Overflow: return a builder pointing at the last slot (no-op writes)
        return ToolBuilder(&_tools[JELTZ_MAX_TOOLS - 1]);
    }

    /**
     * Configure the health check. The gateway periodically sends cmd and
     * expects the exact string back.
     */
    void health(const char* cmd, const char* expected, uint16_t intervalMs = 10000) {
        _healthCmd = cmd;
        _healthExpect = expected;
        _healthIntervalMs = intervalMs;
    }

    /**
     * Start listening on the given serial port. Call after registering
     * all tools and health config.
     */
    void begin(Stream& serial) {
        _serial = &serial;
    }

    /**
     * Check if cmd is a Jeltz protocol command (JELTZ_DESCRIBE or health
     * check). If so, handles it and returns true. Otherwise returns false
     * and the firmware should handle the command.
     */
    bool handle(const String& cmd) {
        if (cmd == JELTZ_DESCRIBE_CMD) {
            _sendDescribe();
            return true;
        }
        if (_healthCmd && cmd == _healthCmd) {
            if (_serial) {
                _serial->println(_healthExpect);
            }
            return true;
        }
        return false;
    }

    /**
     * Extract a positional argument from a command string.
     * arg("READ 2 fast", 0) returns "2"
     * arg("READ 2 fast", 1) returns "fast"
     * Returns empty string if index is out of bounds.
     */
    static String arg(const String& cmd, uint8_t index) {
        int start = 0;
        uint8_t current = 0;

        // Skip the command word itself
        start = cmd.indexOf(' ');
        if (start < 0) return String();
        start++; // past the space

        // Skip to the requested argument index
        while (current < index) {
            int next = cmd.indexOf(' ', start);
            if (next < 0) return String();
            start = next + 1;
            current++;
        }

        // Extract until next space or end of string
        int end = cmd.indexOf(' ', start);
        if (end < 0) {
            return cmd.substring(start);
        }
        return cmd.substring(start, end);
    }

    uint8_t toolCount() const { return _toolCount; }
    const char* name() const { return _name; }

private:
    const char* _name;
    const char* _desc;
    Stream* _serial;
    JeltzTool _tools[JELTZ_MAX_TOOLS];
    uint8_t _toolCount;
    const char* _healthCmd;
    const char* _healthExpect;
    uint16_t _healthIntervalMs;

    /**
     * Serialize the device description as compact JSON and write it
     * directly to the serial port. No intermediate buffer needed —
     * ArduinoJson streams to the Print interface.
     */
    void _sendDescribe() {
        if (!_serial) return;

        JsonDocument doc;

        doc["v"] = JELTZ_PROTOCOL_VERSION;
        doc["name"] = _name;
        if (_desc && _desc[0] != '\0') {
            doc["desc"] = _desc;
        }

        // Health config
        if (_healthCmd) {
            JsonObject h = doc["health"].to<JsonObject>();
            h["cmd"] = _healthCmd;
            h["expect"] = _healthExpect;
            h["ms"] = _healthIntervalMs;
        }

        // Tools
        JsonArray toolsArr = doc["tools"].to<JsonArray>();
        for (uint8_t i = 0; i < _toolCount; i++) {
            const JeltzTool& t = _tools[i];
            JsonObject toolObj = toolsArr.add<JsonObject>();

            toolObj["name"] = t.name;
            if (t.desc && t.desc[0] != '\0') {
                toolObj["desc"] = t.desc;
            }
            if (t.cmd) {
                toolObj["cmd"] = t.cmd;
            }

            // Parameters
            if (t.paramCount > 0) {
                JsonObject paramsObj = toolObj["params"].to<JsonObject>();
                for (uint8_t j = 0; j < t.paramCount; j++) {
                    const JeltzParam& p = t.params[j];
                    JsonObject paramObj = paramsObj[p.name].to<JsonObject>();
                    paramObj["type"] = p.type;
                    if (p.desc) {
                        paramObj["desc"] = p.desc;
                    }
                    if (p.hasRange) {
                        paramObj["min"] = p.minVal;
                        paramObj["max"] = p.maxVal;
                    }
                }
            }

            // Returns
            if (t.hasReturns) {
                JsonObject retObj = toolObj["returns"].to<JsonObject>();
                retObj["type"] = t.returns.type;
                if (t.returns.unit) {
                    retObj["unit"] = t.returns.unit;
                }
            }
        }

        // Stream compact JSON directly to serial, followed by newline
        serializeJson(doc, *_serial);
        _serial->println();
    }
};

