/*
 * basic_sensor — DHT22 temperature and humidity via Jeltz.
 *
 * Wiring (ESP32):
 *   DHT22 DATA → GPIO 4 (with 10k pull-up to 3.3V)
 *   DHT22 VCC  → 3.3V
 *   DHT22 GND  → GND
 *
 * On the gateway:
 *   jeltz start -p profiles --probe /dev/ttyUSB0
 *
 * The gateway discovers this device automatically and exposes:
 *   dht22_sensor.get_temperature
 *   dht22_sensor.get_humidity
 */

#include <Jeltz.h>
#include <DHT.h>

#define DHT_PIN 4
#define DHT_TYPE DHT22

DHT dht(DHT_PIN, DHT_TYPE);
Jeltz babel("dht22_sensor", "DHT22 temperature and humidity sensor");

void setup() {
    Serial.begin(115200);
    dht.begin();

    babel.tool("get_temperature", "Get current temperature in Celsius")
         .command("READ_TEMP")
         .returns("float", "celsius");

    babel.tool("get_humidity", "Get current relative humidity percentage")
         .command("READ_HUMID")
         .returns("float", "percent");

    babel.health("PING", "PONG");
    babel.begin(Serial);
}

void loop() {
    if (Serial.available()) {
        String cmd = Serial.readStringUntil('\n');
        cmd.trim();

        // Jeltz handles JELTZ_DESCRIBE and PING internally
        if (babel.handle(cmd)) return;

        if (cmd == "READ_TEMP") {
            float temp = dht.readTemperature();
            if (isnan(temp)) {
                Serial.println("ERROR: sensor read failed");
            } else {
                Serial.println(temp);
            }
        } else if (cmd == "READ_HUMID") {
            float humid = dht.readHumidity();
            if (isnan(humid)) {
                Serial.println("ERROR: sensor read failed");
            } else {
                Serial.println(humid);
            }
        }
    }
}

