/*
 * multi_channel — ADC readings with parameterized tool commands.
 *
 * Demonstrates tools with parameters. The gateway interpolates
 * {channel} into the command template before sending, so this
 * device receives "READ 0\n", "READ 1\n", etc.
 *
 * Wiring (ESP32):
 *   Analog sensors on GPIO 32-35 (ADC1 channels 4-7)
 *
 * On the gateway:
 *   jeltz start -p profiles --probe /dev/ttyUSB0
 *
 * Exposes:
 *   adc_reader.read_channel (with channel parameter 0-3)
 *   adc_reader.read_all
 */

#include <Jeltz.h>

const int ADC_PINS[] = {32, 33, 34, 35};
const int NUM_CHANNELS = 4;
const float VREF = 3.3;
const float ADC_MAX = 4095.0;

Jeltz babel("adc_reader", "4-channel ADC reader");

void setup() {
    Serial.begin(115200);

    for (int i = 0; i < NUM_CHANNELS; i++) {
        pinMode(ADC_PINS[i], INPUT);
    }

    babel.tool("read_channel", "Read voltage on a specific ADC channel")
         .command("READ {channel}")
         .param("channel", "int", "ADC channel number", 0, 3)
         .returns("float", "volts");

    babel.tool("read_all", "Read all 4 ADC channels at once")
         .command("READ_ALL")
         .returns("str", "volts");

    babel.health("PING", "PONG");
    babel.begin(Serial);
}

float readVoltage(int channel) {
    if (channel < 0 || channel >= NUM_CHANNELS) return -1.0;
    int raw = analogRead(ADC_PINS[channel]);
    return (raw / ADC_MAX) * VREF;
}

void loop() {
    if (Serial.available()) {
        String cmd = Serial.readStringUntil('\n');
        cmd.trim();

        if (babel.handle(cmd)) return;

        if (cmd.startsWith("READ ")) {
            // Parameterized: "READ 2" → channel 2
            String chStr = Jeltz::arg(cmd, 0);
            int channel = chStr.toInt();
            float voltage = readVoltage(channel);
            if (voltage < 0) {
                Serial.println("ERROR: invalid channel");
            } else {
                Serial.println(voltage, 4);
            }
        } else if (cmd == "READ_ALL") {
            // Return comma-separated voltages
            for (int i = 0; i < NUM_CHANNELS; i++) {
                if (i > 0) Serial.print(",");
                Serial.print(readVoltage(i), 4);
            }
            Serial.println();
        }
    }
}

